module adder_8bit(
    input [7:0] a,
    input [7:0] b,
    input cin,
    output [7:0] sum,
    output cout
);

    wire [3:0] sum_low, sum_high;
    wire carry;

    // Least significant bits
    assign {carry, sum_low} = a[3:0] + b[3:0] + cin;

    // Most significant bits
    assign {cout, sum_high} = a[7:4] + b[7:4] + carry;

    // Concatenate the results
    assign sum = {sum_high, sum_low};

endmodule
